sql:
SELECT COUNT(*) AS total_simulations
   FROM policy_simulations
   WHERE user_id = 0;

SELECT country_id, AVG(hours_worked) AS avg_hours_worked
FROM labor_statistics
GROUP BY country_id;

SELECT country_id, gdp_per_hour
FROM labor_statistics
WHERE country_id = 1;

